import SwiftUI
struct SettingsView: View { @EnvironmentObject var settings: AppSettings; var body: some View { Form { Picker("Verification mode", selection:$settings.verificationModeRaw){ ForEach(VerificationMode.allCases){ Text($0.label).tag($0.rawValue) } }; Toggle("Preserve source folder structure", isOn:$settings.preserveSourceStructure); Picker("Thumbnail quality", selection:$settings.thumbnailQualityRaw){ ForEach(ThumbnailQuality.allCases){ Text($0.rawValue.capitalized).tag($0.rawValue) } }; Toggle("Show hidden technical details", isOn:$settings.showTechnicalDetails); Toggle("Include Proxy Files", isOn:$settings.includeProxyFiles) }.padding().frame(width:420) } }
